comments.body:
Aha, you're right. So in the browser the way to get the error is:
```js
(function () {
  "use strict"
  class Base {
    method() {}
  }

  Object.defineProperty(Base.prototype, "method", {
    value: Base.prototype.method,
    writable: false,
  });

  class SafeExtended extends Base {
    method() {}
  }

  class Extended extends Base {
    static {
      this.prototype.method = function method() {};
    }
  }
})();
```
Firefox calls it `TypeError: "method" is read-only`

I needed to do this as part of the implementation for a language runtime, so I was quite thankful to learn that there does exist a workaround. For my needs, it was enough.

```js
(function () {
  "use strict"
  class Base {
    method() {}
  }

  Object.freeze(Base.prototype);

  class Extended extends Base {
    static {
      Object.defineProperty(this.prototype, 'method', { value: function method() {} });
    }
  }
})();
```

